module comparator(
    input [3:0] a,
    input [3:0] b,

    output reg b_le_a,
    output reg a_eq_b,
    output reg a_lt_b
);
    always @(*) begin
        if (a > b) begin
            b_le_a <= 1;
            a_eq_b <= 0;
            a_lt_b <= 0;
        end else if (a == b) begin
            b_le_a <= 0;
            a_eq_b <= 1;
            a_lt_b <= 0;
        end else begin
            b_le_a <= 0;
            a_eq_b <= 0;
            a_lt_b <= 1;
        end
    end
endmodule
